   353→type rateLimiter struct {
   354→	sync.Mutex
   355→	description string
   356→	rps         float64
   357→	balance     float64
   358→	maxBalance  float64
   359→	lastTick    time.Time
   360→
   361→	now func() time.Time
   362→}
   363→
   364→func newRateLimiter(rps float64) *rateLimiter {
   365→	return &rateLimiter{
   366→		rps:         rps,
   367→		description: fmt.Sprintf("RateLimitingSampler{%g}", rps),
   368→		balance:     math.Max(rps, 1),
   369→		maxBalance:  math.Max(rps, 1),
   370→		lastTick:    time.Now(),
   371→		now:         time.Now,
   372→	}
   373→}
   374→
   375→func (rl *rateLimiter) ShouldSample(p tracesdk.SamplingParameters) tracesdk.SamplingResult {
   376→	rl.Lock()
   377→	defer rl.Unlock()
   378→	psc := trace.SpanContextFromContext(p.ParentContext)
   379→	if rl.balance >= 1 {
   380→		rl.balance -= 1
   381→		return tracesdk.SamplingResult{Decision: tracesdk.RecordAndSample, Tracestate: psc.TraceState()}
   382→	}
   383→	currentTime := rl.now()
   384→	elapsedTime := currentTime.Sub(rl.lastTick).Seconds()
   385→	rl.lastTick = currentTime
   386→	rl.balance = math.Min(rl.maxBalance, rl.balance+elapsedTime*rl.rps)
   387→	if rl.balance >= 1 {
   388→		rl.balance -= 1
   389→		return tracesdk.SamplingResult{Decision: tracesdk.RecordAndSample, Tracestate: psc.TraceState()}
   390→	}
   391→	return tracesdk.SamplingResult{Decision: tracesdk.Drop, Tracestate: psc.TraceState()}
   392→}
   393→
   394→func (rl *rateLimiter) Description() string { return rl.description }
