   396→func TraceIDFromContext(ctx context.Context, requireSampled bool) string {
   397→	spanCtx := trace.SpanContextFromContext(ctx)
   398→	if !spanCtx.HasTraceID() || !spanCtx.IsValid() || (requireSampled && !spanCtx.IsSampled()) {
   399→		return ""
   400→	}
   401→
   402→	return spanCtx.TraceID().String()
   403→}
