   414→// Error sets the status to error and record the error as an exception in the provided span.
   415→func Error(span trace.Span, err error) error {
   416→	attr := []attribute.KeyValue{}
   417→	grafanaErr := errutil.Error{}
   418→	if errors.As(err, &grafanaErr) {
   419→		attr = append(attr, attribute.String("message_id", grafanaErr.MessageID))
   420→	}
   421→
   422→	span.SetStatus(codes.Error, err.Error())
   423→	span.RecordError(err, trace.WithAttributes(attr...))
   424→	return err
   425→}
   426→
   427→// Errorf wraps fmt.Errorf and also sets the status to error and record the error as an exception in the provided span.
   428→func Errorf(span trace.Span, format string, args ...any) error {
   429→	err := fmt.Errorf(format, args...)
   430→	return Error(span, err)
   431→}
